<template><div class="mx-auto mt-16 max-w-md"><UCard><template #header><h1 class="text-xl font-semibold">Student portal</h1></template><form class="space-y-4" @submit.prevent="login"><UFormField label="Portal username"><UInput v-model="username" required /></UFormField><UFormField label="Password"><UInput v-model="password" type="password" required /></UFormField><UButton type="submit" class="w-full" :loading="loading">Sign in</UButton></form></UCard></div></template>
<script setup lang="ts">definePageMeta({ layout: 'auth' }); const username = ref(''); const password = ref(''); const loading = ref(false); const toast = useToast(); const router = useRouter(); const { fetch } = useUserSession(); async function login() { loading.value = true; try { await $fetch('/api/portal/login', { method: 'POST', body: { username: username.value, password: password.value } }); await fetch(); router.push('/portal') } catch (error: any) { toast.add({ color: 'error', title: 'Login failed', description: error.data?.statusMessage || 'Invalid credentials' }) } finally { loading.value = false } }</script>
